212	        try Lockfile.Buffers.writeArray(
213	            StreamType,
214	            stream,
215	            @TypeOf(writer),
216	            writer,
217	            []String,
218	            this.catalogs.groups.keys(),
219	        );
220	
221	        for (this.catalogs.groups.values()) |catalog_deps| {
222	            try Lockfile.Buffers.writeArray(
223	                StreamType,
224	                stream,
225	                @TypeOf(writer),
226	                writer,
227	                []String,
228	                catalog_deps.keys(),
229	            );
230	
231	            try external_deps_buf.ensureTotalCapacity(z_allocator, catalog_deps.count());
232	            external_deps_buf.items.len = catalog_deps.count();
233	            defer external_deps_buf.clearRetainingCapacity();
234	
235	            for (external_deps_buf.items, catalog_deps.values()) |*dest, src| {
236	                dest.* = src.toExternal();
237	            }
238	
239	            try Lockfile.Buffers.writeArray(
240	                StreamType,
241	                stream,
242	                @TypeOf(writer),
243	                writer,
244	                []Dependency.External,
245	                external_deps_buf.items,
246	            );
247	        }
248	    }
249	
250	    try writer.writeAll(std.mem.asBytes(&has_config_version_tag));
251	    const config_version: bun.ConfigVersion = options.config_version orelse .current;
252	    try writer.writeInt(u64, @intFromEnum(config_version), .little);
253	
254	    total_size.* = try stream.getPos();
255	
256	    try writer.writeAll(&alignment_bytes_to_repeat_buffer);
257	}
258	
259	pub const SerializerLoadResult = struct {
260	    packages_need_update: bool = false,
260	    packages_need_update: bool = false,
261	    migrated_from_lockb_v2: bool = false,
262	};
263	
264	pub fn load(
265	    lockfile: *Lockfile,
266	    stream: *Stream,
267	    allocator: Allocator,
268	    log: *logger.Log,
269	    manager: ?*PackageManager,
270	) !SerializerLoadResult {
271	    var res = SerializerLoadResult{};
272	    var reader = stream.reader();
273	    var header_buf_: [header_bytes.len]u8 = undefined;
274	    const header_buf = header_buf_[0..try reader.readAll(&header_buf_)];
275	
276	    if (!strings.eqlComptime(header_buf, header_bytes)) {
277	        return error.InvalidLockfile;
278	    }
279	
280	    var migrate_from_v2 = false;
281	    const format = try reader.readInt(u32, .little);
282	    if (format > @intFromEnum(Lockfile.FormatVersion.current)) {
283	        return error.@"Unexpected lockfile version";
284	    }
285	
286	    if (format < @intFromEnum(Lockfile.FormatVersion.current)) {
287	
288	        // we only allow migrating from v2 to v3 or above
289	        if (format != @intFromEnum(Lockfile.FormatVersion.v2)) {
290	            return error.@"Outdated lockfile version";
291	        }
292	
293	        migrate_from_v2 = true;
294	    }
295	
296	    lockfile.format = Lockfile.FormatVersion.current;
297	    lockfile.allocator = allocator;
298	
299	    _ = try reader.readAll(&lockfile.meta_hash);
300	
301	    const total_buffer_size = try reader.readInt(u64, .little);
302	    if (total_buffer_size > stream.buffer.len) {
303	        return error.@"Lockfile is missing data";
304	    }
305	
306	    const packages_load_result = try Lockfile.Package.Serializer.load(
307	        stream,
308	        total_buffer_size,
309	        allocator,
310	        migrate_from_v2,
311	    );
312	
313	    lockfile.packages = packages_load_result.list;
314	
315	    res.packages_need_update = packages_load_result.needs_update;
316	    res.migrated_from_lockb_v2 = migrate_from_v2;
317	
318	    lockfile.buffers = try Lockfile.Buffers.load(
319	        stream,
320	        allocator,
321	        log,
322	        manager,
323	    );
324	    if ((try stream.reader().readInt(u64, .little)) != 0) {
325	        return error.@"Lockfile is malformed (expected 0 at the end)";
326	    }
327	
328	    const has_workspace_name_hashes = false;
329	    // < Bun v1.0.4 stopped right here when reading the lockfile
330	    // So we add an extra 8 byte tag to say "hey, there's more data here"
331	    {
332	        const remaining_in_buffer = total_buffer_size -| stream.pos;
333	
334	        if (remaining_in_buffer > 8 and total_buffer_size <= stream.buffer.len) {
335	            const next_num = try reader.readInt(u64, .little);
336	            if (next_num == has_workspace_package_ids_tag) {
337	                {
338	                    var workspace_package_name_hashes = try Lockfile.Buffers.readArray(
339	                        stream,
340	                        allocator,
341	                        std.ArrayListUnmanaged(PackageNameHash),
342	                    );
343	                    defer workspace_package_name_hashes.deinit(allocator);
344	
345	                    var workspace_versions_list = workspace_versions_list: {
346	                        if (!migrate_from_v2) {
347	                            break :workspace_versions_list try Lockfile.Buffers.readArray(
348	                                stream,
349	                                allocator,
350	                                std.ArrayListUnmanaged(Semver.Version),
351	                            );
352	                        }
353	
354	                        var old_versions_list = try Lockfile.Buffers.readArray(
355	                            stream,
356	                            allocator,
357	                            std.ArrayListUnmanaged(Semver.VersionType(u32)),
358	                        );
359	                        defer old_versions_list.deinit(allocator);
360	
361	                        var versions_list: std.ArrayListUnmanaged(Semver.Version) = try .initCapacity(allocator, old_versions_list.items.len);
362	                        for (old_versions_list.items) |old_version| {
363	                            versions_list.appendAssumeCapacity(old_version.migrate());
364	                        }
365	
366	                        break :workspace_versions_list versions_list;
367	                    };
368	
369	                    comptime {
370	                        if (PackageNameHash != @TypeOf((VersionHashMap.KV{ .key = undefined, .value = undefined }).key)) {
371	                            @compileError("VersionHashMap must be in sync with serialization");
372	                        }
373	                        if (Semver.Version != @TypeOf((VersionHashMap.KV{ .key = undefined, .value = undefined }).value)) {
374	                            @compileError("VersionHashMap must be in sync with serialization");
375	                        }
376	                    }
377	                    defer workspace_versions_list.deinit(allocator);
378	                    try lockfile.workspace_versions.ensureTotalCapacity(allocator, workspace_versions_list.items.len);
379	                    lockfile.workspace_versions.entries.len = workspace_versions_list.items.len;
380	                    @memcpy(lockfile.workspace_versions.keys(), workspace_package_name_hashes.items);
381	                    @memcpy(lockfile.workspace_versions.values(), workspace_versions_list.items);
382	                    try lockfile.workspace_versions.reIndex(allocator);
383	                }
384	
385	                {
386	                    var workspace_paths_hashes = try Lockfile.Buffers.readArray(
387	                        stream,
388	                        allocator,
389	                        std.ArrayListUnmanaged(PackageNameHash),
390	                    );
391	                    defer workspace_paths_hashes.deinit(allocator);
392	                    var workspace_paths_strings = try Lockfile.Buffers.readArray(
393	                        stream,
394	                        allocator,
395	                        std.ArrayListUnmanaged(String),
396	                    );
397	                    defer workspace_paths_strings.deinit(allocator);
398	
399	                    try lockfile.workspace_paths.ensureTotalCapacity(allocator, workspace_paths_strings.items.len);
400	
401	                    lockfile.workspace_paths.entries.len = workspace_paths_strings.items.len;
402	                    @memcpy(lockfile.workspace_paths.keys(), workspace_paths_hashes.items);
403	                    @memcpy(lockfile.workspace_paths.values(), workspace_paths_strings.items);
404	                    try lockfile.workspace_paths.reIndex(allocator);
405	                }
406	            } else {
407	                stream.pos -= 8;
408	            }
409	        }
410	    }
411	
412	    {
413	        const remaining_in_buffer = total_buffer_size -| stream.pos;
414	
415	        // >= because `has_empty_trusted_dependencies_tag` is tag only
416	        if (remaining_in_buffer >= 8 and total_buffer_size <= stream.buffer.len) {
417	            const next_num = try reader.readInt(u64, .little);
418	            if (remaining_in_buffer > 8 and next_num == has_trusted_dependencies_tag) {
419	                var trusted_dependencies_hashes = try Lockfile.Buffers.readArray(
420	                    stream,
421	                    allocator,
422	                    std.ArrayListUnmanaged(u32),
423	                );
424	                defer trusted_dependencies_hashes.deinit(allocator);
425	
426	                lockfile.trusted_dependencies = .{};
427	                try lockfile.trusted_dependencies.?.ensureTotalCapacity(allocator, trusted_dependencies_hashes.items.len);
428	
429	                lockfile.trusted_dependencies.?.entries.len = trusted_dependencies_hashes.items.len;
430	                @memcpy(lockfile.trusted_dependencies.?.keys(), trusted_dependencies_hashes.items);
431	                try lockfile.trusted_dependencies.?.reIndex(allocator);
432	            } else if (next_num == has_empty_trusted_dependencies_tag) {
433	                // trusted dependencies exists in package.json but is an empty array.
434	                lockfile.trusted_dependencies = .{};
435	            } else {
436	                stream.pos -= 8;
437	            }
438	        }
439	    }
440	
441	    {
442	        const remaining_in_buffer = total_buffer_size -| stream.pos;
443	
444	        if (remaining_in_buffer > 8 and total_buffer_size <= stream.buffer.len) {
445	            const next_num = try reader.readInt(u64, .little);
446	            if (next_num == has_overrides_tag) {
447	                var overrides_name_hashes = try Lockfile.Buffers.readArray(
448	                    stream,
449	                    allocator,
450	                    std.ArrayListUnmanaged(PackageNameHash),
451	                );
452	                defer overrides_name_hashes.deinit(allocator);
453	
454	                var map = lockfile.overrides.map;
455	                defer lockfile.overrides.map = map;
456	
457	                try map.ensureTotalCapacity(allocator, overrides_name_hashes.items.len);
458	                const override_versions_external = try Lockfile.Buffers.readArray(
459	                    stream,
460	                    allocator,
461	                    std.ArrayListUnmanaged(Dependency.External),
462	                );
463	                const context: Dependency.Context = .{
464	                    .allocator = allocator,
465	                    .log = log,
466	                    .buffer = lockfile.buffers.string_bytes.items,
467	                    .package_manager = manager,
468	                };
469	                for (overrides_name_hashes.items, override_versions_external.items) |name, value| {
470	                    map.putAssumeCapacity(name, Dependency.toDependency(value, context));
471	                }
472	            } else {
473	                stream.pos -= 8;
474	            }
475	        }
476	    }
477	
478	    {
479	        const remaining_in_buffer = total_buffer_size -| stream.pos;
480	
481	        if (remaining_in_buffer > 8 and total_buffer_size <= stream.buffer.len) {
482	            const next_num = try reader.readInt(u64, .little);
483	            if (next_num == has_patched_dependencies_tag) {
484	                var patched_dependencies_name_and_version_hashes =
485	                    try Lockfile.Buffers.readArray(
486	                        stream,
487	                        allocator,
488	                        std.ArrayListUnmanaged(PackageNameAndVersionHash),
489	                    );
490	                defer patched_dependencies_name_and_version_hashes.deinit(allocator);
491	
492	                var map = lockfile.patched_dependencies;
493	                defer lockfile.patched_dependencies = map;
494	
495	                try map.ensureTotalCapacity(allocator, patched_dependencies_name_and_version_hashes.items.len);
496	                const patched_dependencies_paths = try Lockfile.Buffers.readArray(
497	                    stream,
498	                    allocator,
499	                    std.ArrayListUnmanaged(PatchedDep),
500	                );
501	
502	                for (patched_dependencies_name_and_version_hashes.items, patched_dependencies_paths.items) |name_hash, patch_path| {
503	                    map.putAssumeCapacity(name_hash, patch_path);
504	                }
505	            } else {
506	                stream.pos -= 8;
507	            }
508	        }
509	    }
510	
511	    {
512	        const remaining_in_buffer = total_buffer_size -| stream.pos;
513	
514	        if (remaining_in_buffer > 8 and total_buffer_size <= stream.buffer.len) {
515	            const next_num = try reader.readInt(u64, .little);
516	            if (next_num == has_catalogs_tag) {
517	                lockfile.catalogs = .{};
518	
519	                var default_dep_names = try Lockfile.Buffers.readArray(stream, allocator, std.ArrayListUnmanaged(String));
520	                defer default_dep_names.deinit(allocator);
521	
522	                var default_deps = try Lockfile.Buffers.readArray(stream, allocator, std.ArrayListUnmanaged(Dependency.External));
523	                defer default_deps.deinit(allocator);
524	
525	                try lockfile.catalogs.default.ensureTotalCapacity(allocator, default_deps.items.len);
526	
527	                const context: Dependency.Context = .{
528	                    .allocator = allocator,
529	                    .log = log,
530	                    .buffer = lockfile.buffers.string_bytes.items,
531	                    .package_manager = manager,
532	                };
533	
534	                for (default_dep_names.items, default_deps.items) |dep_name, dep| {
535	                    lockfile.catalogs.default.putAssumeCapacityContext(dep_name, Dependency.toDependency(dep, context), String.arrayHashContext(lockfile, null));
536	                }
537	
538	                var catalog_names = try Lockfile.Buffers.readArray(stream, allocator, std.ArrayListUnmanaged(String));
539	                defer catalog_names.deinit(allocator);
540	
541	                try lockfile.catalogs.groups.ensureTotalCapacity(allocator, catalog_names.items.len);
542	
543	                for (catalog_names.items) |catalog_name| {
544	                    var catalog_dep_names = try Lockfile.Buffers.readArray(stream, allocator, std.ArrayListUnmanaged(String));
545	                    defer catalog_dep_names.deinit(allocator);
546	
547	                    var catalog_deps = try Lockfile.Buffers.readArray(stream, allocator, std.ArrayListUnmanaged(Dependency.External));
548	                    defer catalog_deps.deinit(allocator);
549	
550	                    const group = try lockfile.catalogs.getOrPutGroup(lockfile, catalog_name);
551	
552	                    try group.ensureTotalCapacity(allocator, catalog_deps.items.len);
553	
554	                    for (catalog_dep_names.items, catalog_deps.items) |dep_name, dep| {
555	                        group.putAssumeCapacityContext(dep_name, Dependency.toDependency(dep, context), String.arrayHashContext(lockfile, null));
556	                    }
557	                }
558	            } else {
559	                stream.pos -= 8;
560	            }

560	            }
561	        }
562	    }
563	
564	    {
565	        const remaining_in_buffer = total_buffer_size -| stream.pos;
566	
567	        if (remaining_in_buffer > 8 and total_buffer_size <= stream.buffer.len) {
568	            const next_num = try reader.readInt(u64, .little);
569	            if (next_num == has_config_version_tag) {
570	                const config_version = bun.ConfigVersion.fromInt(try reader.readInt(u64, .little)) orelse {
571	                    return error.InvalidLockfile;
572	                };
573	                lockfile.saved_config_version = config_version;
574	            }
575	        }
576	    }
577	
578	    lockfile.scratch = Lockfile.Scratch.init(allocator);
579	    lockfile.package_index = PackageIndex.Map.initContext(allocator, .{});
580	    lockfile.string_pool = StringPool.init(allocator);
581	    try lockfile.package_index.ensureTotalCapacity(@as(u32, @truncate(lockfile.packages.len)));
582	
583	    if (!has_workspace_name_hashes) {
584	        const slice = lockfile.packages.slice();
585	        const name_hashes = slice.items(.name_hash);
586	        const resolutions = slice.items(.resolution);
587	        for (name_hashes, resolutions, 0..) |name_hash, resolution, id| {
588	            try lockfile.getOrPutID(@as(PackageID, @truncate(id)), name_hash);
589	
590	            // compatibility with < Bun v1.0.4
591	            switch (resolution.tag) {
592	                .workspace => {
593	                    try lockfile.workspace_paths.put(allocator, name_hash, resolution.value.workspace);
594	                },
595	                else => {},
596	            }
597	        }
598	    } else {
599	        const slice = lockfile.packages.slice();
600	        const name_hashes = slice.items(.name_hash);
601	        for (name_hashes, 0..) |name_hash, id| {
602	            try lockfile.getOrPutID(@as(PackageID, @truncate(id)), name_hash);
603	        }
604	    }
605	
606	    if (comptime Environment.allow_assert) assert(stream.pos == total_buffer_size);
607	
608	    // const end = try reader.readInt(u64, .little);
609	    return res;
610	}
